import React, { useCallback, useLayoutEffect, useRef } from 'react';
import { TextArea } from '@linm-soft-org/linm-web-common-components';
import {
  VOUCHER_DESCRIPTION_MAX_LENGTH,
  VOUCHER_DESCRIPTION_MAX_ROWS,
  VOUCHER_DESCRIPTION_MIN_ROWS,
} from './voucherDescriptionConstants';
import styles from './VoucherDescriptionField.module.css';

export {
  VOUCHER_DESCRIPTION_MIN_ROWS,
  VOUCHER_DESCRIPTION_MAX_ROWS,
  VOUCHER_DESCRIPTION_MAX_LENGTH,
  voucherDescriptionMaxLengthMessage,
} from './voucherDescriptionConstants';

/** Auto-grow height: min → max lines, then vertical scroll. */
export function syncVoucherDescriptionHeight(
  textarea: HTMLTextAreaElement,
  minRows = VOUCHER_DESCRIPTION_MIN_ROWS,
  maxRows = VOUCHER_DESCRIPTION_MAX_ROWS,
): void {
  textarea.style.height = 'auto';
  const computed = getComputedStyle(textarea);
  const lineHeight = parseFloat(computed.lineHeight) || 20;
  const pad = parseFloat(computed.paddingTop) + parseFloat(computed.paddingBottom);
  const border = parseFloat(computed.borderTopWidth) + parseFloat(computed.borderBottomWidth);
  const minH = lineHeight * minRows + pad + border;
  const maxH = lineHeight * maxRows + pad + border;
  const contentH = textarea.scrollHeight;
  const next = Math.min(Math.max(contentH, minH), maxH);
  textarea.style.height = `${next}px`;
  textarea.style.overflowY = contentH > maxH ? 'auto' : 'hidden';
}

export interface VoucherDescriptionFieldProps {
  value: string;
  onChange: (value: string) => void;
  error?: string;
  readOnly?: boolean;
  disabled?: boolean;
  placeholder?: string;
  /** Default `VOUCHER_DESCRIPTION_MAX_LENGTH` (4000). */
  maxLength?: number;
  /** Số dòng tối thiểu (auto-grow). Default `VOUCHER_DESCRIPTION_MIN_ROWS` (2). */
  minRows?: number;
  /** Số dòng tối đa trước khi scroll. Default `VOUCHER_DESCRIPTION_MAX_ROWS` (5). */
  maxRows?: number;
  /** Hiển thị «Còn N ký tự» dưới ô nhập. Default true. */
  showRemainingCount?: boolean;
  id?: string;
  'data-testid'?: string;
  className?: string;
}

export const VoucherDescriptionField: React.FC<VoucherDescriptionFieldProps> = ({
  value,
  onChange,
  error,
  readOnly,
  disabled,
  placeholder,
  maxLength = VOUCHER_DESCRIPTION_MAX_LENGTH,
  minRows = VOUCHER_DESCRIPTION_MIN_ROWS,
  maxRows = VOUCHER_DESCRIPTION_MAX_ROWS,
  showRemainingCount = true,
  id,
  'data-testid': testId,
  className,
}) => {
  const wrapRef = useRef<HTMLDivElement>(null);
  const inactive = readOnly || disabled;
  const remaining = Math.max(0, maxLength - value.length);
  const warnThreshold = Math.min(200, Math.floor(maxLength * 0.05));

  const syncHeight = useCallback(() => {
    const textarea = wrapRef.current?.querySelector('textarea');
    if (textarea) syncVoucherDescriptionHeight(textarea, minRows, maxRows);
  }, [minRows, maxRows]);

  useLayoutEffect(() => {
    syncHeight();
  }, [value, syncHeight]);

  const remainingClass = [
    styles.remaining,
    remaining === 0 ? styles.remainingLimit : remaining <= warnThreshold ? styles.remainingWarn : '',
  ]
    .filter(Boolean)
    .join(' ');

  return (
    <div ref={wrapRef} className={styles.wrap}>
      <TextArea
        id={id}
        data-testid={testId}
        className={[styles.textarea, className].filter(Boolean).join(' ')}
        value={value}
        error={error}
        rows={minRows}
        resize="none"
        maxLength={maxLength}
        readOnly={readOnly}
        disabled={disabled}
        placeholder={placeholder}
        onChange={e => {
          onChange(e.target.value);
          syncHeight();
        }}
        onInput={syncHeight}
      />
      {showRemainingCount && !inactive && (
        <div className={styles.footer}>
          <span
            className={remainingClass}
            data-testid={testId ? `${testId}-remaining` : undefined}
            aria-live="polite"
          >
            {remaining === 0 ? `Đã đạt giới hạn ${maxLength} ký tự` : `Còn ${remaining} ký tự`}
          </span>
        </div>
      )}
    </div>
  );
};
